<code class="code-line odd line-11">        <span class="token punctuation">.</span>imr_multiaddr<span class="token punctuation">.</span>s_addr <span class="token operator">=</span> <span class="token function">inet_addr</span><span class="token punctuation">(</span><span class="token string">&quot;239.239.239.239&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span></code>
